/*
 * Demand Paging Simulator
 * 
 * Simulates a demand-paged virtual memory system with:
 * - Page table with valid-invalid bits
 * - Page fault handling
 * - Frame allocation and replacement
 * - Statistics tracking
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <time.h>

#define NUM_PAGES 16 // Virtual address space: 16 pages
#define NUM_FRAMES 4 // Physical memory: 4 frames
#define PAGE_SIZE 256 // Each page is 256 bytes

// Page Table Entry structure
typedef struct {
 bool valid; // Valid-Invalid bit (V=1 in memory, I=0 on disk)
 int frame_number; // Frame number in physical memory
 bool referenced; // Referenced bit (R)
 bool dirty; // Modified bit (M)
 int swap_location; // Location on disk (swap space)
} PageTableEntry;

// Frame Table Entry
typedef struct {
 bool occupied; // Is frame in use?
 int process_id; // Which process owns this frame
 int page_number; // Which virtual page is loaded
 bool dirty; // Has frame been modified?
} FrameTableEntry;

// System state
typedef struct {
 PageTableEntry page_table[NUM_PAGES];
 FrameTableEntry frames[NUM_FRAMES];
 int free_frames;
 int page_faults;
 int memory_accesses;
 int disk_writes; // For dirty pages
 int disk_reads; // Page loads from disk
} PagingSystem;

// Initialize the paging system
void init_system(PagingSystem *sys) {
 sys->free_frames = NUM_FRAMES;
 sys->page_faults = 0;
 sys->memory_accesses = 0;
 sys->disk_writes = 0;
 sys->disk_reads = 0;

 // Initialize page table
 for (int i = 0; i < NUM_PAGES; i++) {
 sys->page_table[i].valid = false; // All pages start invalid (not in memory)
 sys->page_table[i].frame_number = -1;
 sys->page_table[i].referenced = false;
 sys->page_table[i].dirty = false;
 sys->page_table[i].swap_location = i; // Page i is at swap location i
 }

 // Initialize frame table
 for (int i = 0; i < NUM_FRAMES; i++) {
 sys->frames[i].occupied = false;
 sys->frames[i].process_id = -1;
 sys->frames[i].page_number = -1;
 sys->frames[i].dirty = false;
 }
}

// Find a free frame (or use replacement)
int get_frame(PagingSystem *sys) {
 // First, try to find a free frame
 for (int i = 0; i < NUM_FRAMES; i++) {
 if (!sys->frames[i].occupied) {
 return i; // Found free frame
 }
 }

 // No free frames - use simple FIFO replacement
 static int next_victim = 0; // Simple circular pointer
 int victim_frame = next_victim;
 next_victim = (next_victim + 1) % NUM_FRAMES;

 // Get the victim page's PTE
 int victim_page = sys->frames[victim_frame].page_number;

 // If dirty, write back to disk
 if (sys->frames[victim_frame].dirty) {
 printf(" [REPLACEMENT] Writing dirty page %d to disk\n", victim_page);
 sys->disk_writes++;
 sys->page_table[victim_page].dirty = false;
 }

 // Invalidate the victim page in its page table
 sys->page_table[victim_page].valid = false;

 printf(" [REPLACEMENT] Evicting page %d from frame %d\n", victim_page, victim_frame);

 return victim_frame;
}

// Handle a page fault
void handle_page_fault(PagingSystem *sys, int page_number) {
 printf(" [PAGE FAULT] Loading page %d into memory\n", page_number);
 sys->page_faults++;

 // Step 1: Find or create a frame
 int frame = get_frame(sys);

 // Step 2: Load page from disk (simulate disk I/O)
 printf(" [DISK I/O] Reading page %d from swap location %d into frame %d\n",
 page_number, sys->page_table[page_number].swap_location, frame);
 sys->disk_reads++;

 // Step 3: Update frame table
 sys->frames[frame].occupied = true;
 sys->frames[frame].page_number = page_number;
 sys->frames[frame].dirty = false;

 // Step 4: Update page table entry
 sys->page_table[page_number].valid = true;
 sys->page_table[page_number].frame_number = frame;
 sys->page_table[page_number].referenced = true;
 sys->page_table[page_number].dirty = false;
}

// Simulate memory access
bool access_memory(PagingSystem *sys, int virtual_address, bool write) {
 sys->memory_accesses++;

 // Extract page number from virtual address
 int page_number = virtual_address / PAGE_SIZE;
 int offset = virtual_address % PAGE_SIZE;

 printf("Accessing VA 0x%03X: Page %d, Offset %d\n", 
 virtual_address, page_number, offset);

 // Check if page is valid and in memory
 if (page_number >= NUM_PAGES) {
 printf(" [ERROR] Invalid address - beyond virtual address space\n");
 return false;
 }

 if (!sys->page_table[page_number].valid) {
 // Page fault occurs!
 handle_page_fault(sys, page_number);
 }

 // Update referenced bit
 sys->page_table[page_number].referenced = true;

 // If write access, set dirty bit
 if (write) {
 sys->page_table[page_number].dirty = true;
 sys->frames[sys->page_table[page_number].frame_number].dirty = true;
 }

 printf(" [SUCCESS] Access completed (frame %d, offset %d)\n",
 sys->page_table[page_number].frame_number, offset);

 return true;
}

// Print system statistics
void print_stats(PagingSystem *sys) {
 printf("\n================== SYSTEM STATISTICS ==================\n");
 printf("Total Memory Accesses: %d\n", sys->memory_accesses);
 printf("Page Faults: %d\n", sys->page_faults);
 printf("Disk Reads: %d\n", sys->disk_reads);
 printf("Disk Writes: %d\n", sys->disk_writes);

 if (sys->memory_accesses > 0) {
 double fault_rate = (double)sys->page_faults / sys->memory_accesses * 100;
 printf("Page Fault Rate: %.2f%%\n", fault_rate);
 }
 printf("=======================================================\n");
}

// Print current state of page table
void print_page_table(PagingSystem *sys) {
 printf("\n=================== PAGE TABLE ===================\n");
 printf("Page\tValid\tFrame\tReferenced\tDirty\n");
 printf("--------------------------------------------------\n");
 for (int i = 0; i < NUM_PAGES; i++) {
 printf("%d\t%d\t%d\t%d\t\t%d\n",
 i,
 sys->page_table[i].valid,
 sys->page_table[i].frame_number,
 sys->page_table[i].referenced,
 sys->page_table[i].dirty);
 }
 printf("===================================================\n");
}

// Main function - demonstrate demand paging
int main() {
 PagingSystem system;
 init_system(&system);

 printf("DEMAND PAGING SIMULATOR\n");
 printf("========================\n");
 printf("Virtual Pages: %d, Physical Frames: %d\n", NUM_PAGES, NUM_FRAMES);
 printf("Page Size: %d bytes\n\n", PAGE_SIZE);

 // Sequence of memory accesses to demonstrate demand paging
 int accesses[] = {0, 256, 512, 768, // Access pages 0, 1, 2, 3
 1024, // Access page 4
 1280, 1536, 1792, // Access pages 5, 6, 7
 256, // Re-access page 1 (should hit)
 2048, 2304, 2560, // Pages 8, 9, 10 (will cause replacement)
 0, 256, 512, 768}; // Re-access earlier pages (more replacements)

 int num_accesses = sizeof(accesses) / sizeof(accesses[0]);

 printf("Running %d memory accesses...\n\n", num_accesses);

 for (int i = 0; i < num_accesses; i++) {
 printf("--- Access #%d ---\n", i + 1);
 access_memory(&system, accesses[i], false);
 printf("\n");
 }

 // Print final statistics
 print_stats(&system);
 print_page_table(&system);

 return 0;
}
